var LOGO="data:image/png;base64,";
var API="https://script.google.com/macros/s/AKfycbyQSvELw0R1KEzizmVkMSUU-bp325eo08UtCIJTUG21LPWEb5J3h2MH6a8jlfVCmEWY4g/exec";

document.addEventListener("DOMContentLoaded",function(){
  document.getElementById("logo").src=LOGO;

  // Tabs
  document.getElementById("t0").onclick=function(){sw(0);};
  document.getElementById("t1").onclick=function(){sw(1);};
  function sw(n){
    [0,1].forEach(function(i){
      document.getElementById("t"+i).classList.toggle("active",i===n);
      document.getElementById("p"+i).classList.toggle("active",i===n);
    });
  }

  // Toast
  function showToast(msg,err){
    var el=document.getElementById("toast");
    el.textContent=msg;
    el.className="toast "+(err?"err":"ok")+" show";
    setTimeout(function(){el.className="toast "+(err?"err":"ok");},3500);
  }

  // Button state
  function loading(id,msg){var b=document.getElementById(id);b.disabled=true;b.innerHTML="<span class='spin'></span>"+msg;}
  function done(id,msg){var b=document.getElementById(id);b.disabled=false;b.innerHTML=msg;}

  // Tier
  function getTier(w){
    if(w>=20)return{n:"Platinum",c:"tp",next:null};
    if(w>=10)return{n:"Gold",c:"tg",next:20};
    if(w>=5)return{n:"Silver",c:"ts",next:10};
    return{n:"Bronze",c:"tb",next:5};
  }

  // JSONP
  function api(params){
    return new Promise(function(resolve,reject){
      var id="cb"+Date.now()+(Math.random()*1e6|0);
      var finished=false;
      var timer=setTimeout(function(){
        if(finished)return; finished=true;
        delete window[id];
        var s=document.getElementById("jsonp"); if(s)s.remove();
        reject("Timeout - Google Sheet did not respond");
      },12000);
      window[id]=function(data){
        if(finished)return; finished=true;
        clearTimeout(timer);
        delete window[id];
        var s=document.getElementById("jsonp"); if(s)s.remove();
        resolve(data);
      };
      var q=Object.keys(params).map(function(k){
        return encodeURIComponent(k)+"="+encodeURIComponent(params[k]);
      }).join("&")+"&callback="+id;
      var s=document.createElement("script");
      s.id="jsonp";
      s.src=API+"?"+q;
      s.onerror=function(){
        if(finished)return; finished=true;
        clearTimeout(timer);
        delete window[id];
        reject("Blocked - Apps Script not deployed correctly");
      };
      document.head.appendChild(s);
    });
  }

  // TEST
  document.getElementById("tbtn").onclick=function(){
    var box=document.getElementById("tbox");
    box.className="tbox show";
    box.innerHTML="<span style='color:var(--muted)'>Connecting...</span>";
    api({action:"lookup",vehicle:"PING"})
      .then(function(d){
        box.innerHTML="<span style='color:var(--success)'>Connected! Sheet is working.</span><br><small style='color:var(--muted)'>"+JSON.stringify(d)+"</small>";
      })
      .catch(function(e){
        box.innerHTML="<span style='color:var(--danger)'>Failed: "+e+"</span><br><br>"+
          "<b>Fix steps:</b><br>"+
          "1. Open Google Sheet<br>"+
          "2. Click Extensions - Apps Script<br>"+
          "3. Delete all code, paste the doGet code<br>"+
          "4. Deploy - Manage Deployments<br>"+
          "5. Pencil icon - New Version - Deploy<br>"+
          "6. Who has access = Anyone";
      });
  };

  // CHECK MEMBERSHIP
  document.getElementById("cbtn").onclick=checkMember;
  document.getElementById("cv").onkeydown=function(e){if(e.key==="Enter")checkMember();};

  function checkMember(){
    var v=document.getElementById("cv").value.trim().toUpperCase().replace(/\s+/g,"");
    if(!v){showToast("Enter vehicle number",true);return;}
    loading("cbtn","Searching...");
    api({action:"lookup",vehicle:v})
      .then(function(d){
        done("cbtn","Check Membership");
        if(d.found) showCustomer(d);
        else document.getElementById("cres").innerHTML=
          "<div class='card'><div style='text-align:center;padding:20px'>"+
          "<div style='font-size:40px;margin-bottom:10px'>&#128269;</div>"+
          "<div style='font-family:Bebas Neue,cursive;font-size:22px;letter-spacing:2px;color:var(--danger)'>NOT FOUND</div>"+
          "<div style='font-size:13px;color:var(--muted);margin-top:6px'>"+v+" is not registered.<br>Ask staff to add you.</div>"+
          "</div></div>";
      })
      .catch(function(){
        done("cbtn","Check Membership");
        showToast("Connection error - use Test Connection button",true);
      });
  }

  function showCustomer(d){
    var w=parseInt(d.count)||0;
    var t=getTier(w);
    var G=25,pct=Math.min(100,Math.round(w/G*100));
    var gap=t.next?t.next-w:0;
    var hist=d.history?String(d.history).split("\n").filter(Boolean):[];
    var ht="";
    if(hist.length){
      ht="<div style='font-size:10px;text-transform:uppercase;letter-spacing:2px;color:var(--muted);margin:14px 0 8px'>Wash History (latest first)</div>"+
        "<table style='width:100%;border-collapse:collapse'>"+
        "<thead><tr>"+
        "<th style='font-size:10px;text-transform:uppercase;color:var(--muted);padding:7px 8px;text-align:left;border-bottom:1px solid var(--border)'>#</th>"+
        "<th style='font-size:10px;text-transform:uppercase;color:var(--muted);padding:7px 8px;text-align:left;border-bottom:1px solid var(--border)'>Date</th>"+
        "<th style='font-size:10px;text-transform:uppercase;color:var(--muted);padding:7px 8px;text-align:left;border-bottom:1px solid var(--border)'>Time</th>"+
        "</tr></thead><tbody>";
      hist.slice().reverse().forEach(function(row,i){
        var p=row.split(", ");
        ht+="<tr>"+
          "<td style='padding:8px;border-bottom:1px solid rgba(42,42,64,.5)'><span style='display:inline-flex;align-items:center;justify-content:center;width:24px;height:24px;border-radius:6px;background:linear-gradient(135deg,var(--accent2),var(--accent));color:#000;font-size:10px;font-weight:700'>"+(hist.length-i)+"</span></td>"+
          "<td style='padding:8px;font-size:13px;border-bottom:1px solid rgba(42,42,64,.5);color:var(--text)'>"+(p[0]||row)+"</td>"+
          "<td style='padding:8px;font-size:11px;border-bottom:1px solid rgba(42,42,64,.5);color:var(--muted)'>"+(p[1]||"")+"</td>"+
          "</tr>";
      });
      ht+="</tbody></table>";
    }
    var ld=d.lastDate?String(d.lastDate).split(",")[0]:"-";
    var rline=t.next?gap+" more wash"+(gap!==1?"es":"")+" to reach "+(t.next===5?"Silver":t.next===10?"Gold":"Platinum"):"Max tier reached! Thank you.";
    document.getElementById("cres").innerHTML=
      "<div class='rcard'>"+
      "<div style='display:flex;align-items:flex-start;gap:12px;margin-bottom:20px'>"+
      "<div style='width:46px;height:46px;background:linear-gradient(135deg,#1e1e35,#2a2a45);border:1px solid var(--border);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0'>&#128100;</div>"+
      "<div style='flex:1'><div style='font-family:Bebas Neue,cursive;font-size:25px;letter-spacing:2px;line-height:1;margin-bottom:4px'>"+d.name+"</div>"+
      "<span style='display:inline-block;background:var(--card);border:1px solid var(--border);border-radius:5px;padding:2px 9px;font-size:11px;letter-spacing:2px;color:var(--accent)'>"+d.vehicle+"</span></div>"+
      "<span class='"+t.c+"'>"+t.n+"</span>"+
      "</div>"+
      "<div style='display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px'>"+
      "<div style='grid-column:1/-1;background:linear-gradient(135deg,rgba(0,212,255,.08),rgba(0,153,204,.04));border:1px solid rgba(0,212,255,.2);border-radius:12px;padding:14px'>"+
      "<div style='font-size:10px;text-transform:uppercase;letter-spacing:2px;color:var(--muted);margin-bottom:3px'>Total Washes</div>"+
      "<div style='font-family:Bebas Neue,cursive;font-size:42px;letter-spacing:2px;color:var(--accent);line-height:1'>"+w+"</div>"+
      "<div style='font-size:11px;color:var(--muted)'>completed</div></div>"+
      "<div style='background:var(--card);border:1px solid var(--border);border-radius:12px;padding:14px'>"+
      "<div style='font-size:10px;text-transform:uppercase;letter-spacing:2px;color:var(--muted);margin-bottom:3px'>Last Wash</div>"+
      "<div style='font-size:18px;font-weight:600;color:var(--text)'>"+ld+"</div></div>"+
      "<div style='background:var(--card);border:1px solid var(--border);border-radius:12px;padding:14px'>"+
      "<div style='font-size:10px;text-transform:uppercase;letter-spacing:2px;color:var(--muted);margin-bottom:3px'>Phone</div>"+
      "<div style='font-size:16px;font-weight:600;color:var(--text)'>"+(d.phone||"-")+"</div></div>"+
      "</div>"+
      "<div style='display:flex;justify-content:space-between;font-size:11px;color:var(--muted);margin-bottom:5px'><span>Progress to "+G+"</span><span>"+w+"/"+G+"</span></div>"+
      "<div style='background:var(--card);border-radius:99px;height:7px;overflow:hidden;margin-bottom:7px'><div style='height:100%;border-radius:99px;background:linear-gradient(90deg,var(--accent2),var(--accent));width:"+pct+"%'></div></div>"+
      "<div style='font-size:12px;color:var(--gold);margin-bottom:14px'>"+rline+"</div>"+
      ht+"</div>";
  }

  // ADD WASH
  document.getElementById("awbtn").onclick=addWash;
  document.getElementById("av").onkeydown=function(e){if(e.key==="Enter")addWash();};

  function addWash(){
    var v=document.getElementById("av").value.trim().toUpperCase().replace(/\s+/g,"");
    if(!v){showToast("Enter vehicle number",true);return;}
    loading("awbtn","Saving...");
    api({action:"addWash",vehicle:v})
      .then(function(d){
        done("awbtn","Add Wash + Save to Sheet");
        if(d.success){showToast("Wash #"+d.count+" saved for "+v);document.getElementById("av").value="";}
        else showToast("Vehicle not found - register first",true);
      })
      .catch(function(){
        done("awbtn","Add Wash + Save to Sheet");
        showToast("Connection error",true);
      });
  }

  // REGISTER
  document.getElementById("arbtn").onclick=function(){
    var name=document.getElementById("an").value.trim();
    var veh=document.getElementById("anv").value.trim().toUpperCase().replace(/\s+/g,"");
    var ph=document.getElementById("aph").value.trim();
    if(!name||!veh){showToast("Name and vehicle required",true);return;}
    loading("arbtn","Registering...");
    api({action:"addWash",vehicle:veh,name:name,phone:ph})
      .then(function(d){
        done("arbtn","Register & Record 1st Wash");
        if(d.success){
          showToast(name+" registered!");
          ["an","anv","aph"].forEach(function(id){document.getElementById(id).value="";});
        }
      })
      .catch(function(){
        done("arbtn","Register & Record 1st Wash");
        showToast("Connection error",true);
      });
  };

  // EXPORT
  document.getElementById("exbtn").onclick=function(){
    showToast("Fetching data...");
    api({action:"export"})
      .then(function(d){
        var rows=(d.rows||[]).map(function(r,i){
          return{"#":i+1,"Vehicle":r[0],"Name":r[1],"Phone":r[2],"Washes":r[3],"Last Wash":r[4],"History":r[5]};
        });
        var ws=XLSX.utils.json_to_sheet(rows);
        ws["!cols"]=[{wch:3},{wch:14},{wch:18},{wch:12},{wch:8},{wch:22},{wch:50}];
        var wb=XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb,ws,"Wash Data");
        XLSX.writeFile(wb,"ShadowsCarWash_"+new Date().toISOString().slice(0,10)+".xlsx");
        showToast("Excel downloaded!");
      })
      .catch(function(){showToast("Export failed",true);});
  };

});
